            "type": "paragraph"
          },
          {
            "attrs": {
              "localId": "1be2262441ce"
            },
            "content": [
              {
                "text": "Acceptance criteria",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* Dispatching the workflow on a complex KAN ticket produces a spec artefact and pauses.",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* A human approval action resumes the workflow into implementation.",
                "type": "text"
              },
              {
                "type": "hardBreak"
              },
              {
                "text": "* Run log committed under .github/agent-logs/senior-dev/DATE/RUN_ID.json.",
                "type": "text"
              }
            ],
            "type": "paragraph"
          }
